import numpy as np
from scipy.spatial import ConvexHull

def convex_hull_4d(points):
    """
    Calculates the convex hull of a set of 4D points.

    Args:
        points (list of lists/tuples or numpy array): A list of 4D points.

    Returns:
        dict: A dictionary containing the following keys:
            - 'vertices': A list of indices into the `points` array representing the vertices of the convex hull.
            - 'simplices': A list of lists of indices into the `points` array, representing the faces (3D tetrahedra) of the convex hull.
            - 'equations': A numpy array of shape (n, 5) where each row represents a hyperplane equation of the form ax + by + cz + dw + e = 0.
            - 'valid': Boolean indicating if the hull was successfully computed. False if input is invalid or hull is degenerate.
            - 'message': String containing information about the hull computation, including error messages.

    Raises:
        TypeError: If the input is not a list of lists/tuples or a numpy array.
        ValueError: If the points are not all 4-dimensional.
    """

    try:
        points = np.array(points)

        if points.ndim != 2:
            return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': "Input must be a 2D array."}

        if points.shape[1] != 4:
            return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': "Points must be 4-dimensional."}

        if points.shape[0] == 0:
            return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': "Input contains no points."}

        if points.shape[0] == 1:
            return {'vertices': [0], 'simplices': [], 'equations': [], 'valid': True, 'message': "Convex hull of a single point."}

        try:
            hull = ConvexHull(points)
            return {
                'vertices': list(hull.vertices),
                'simplices': hull.simplices.tolist(),
                'equations': hull.equations,
                'valid': True,
                'message': "Convex hull computed successfully."
            }
        except Exception as e:
            return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': f"Convex hull computation failed: {str(e)}"}

    except TypeError:
        return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': "Input must be a list of lists/tuples or a numpy array."}
    except ValueError:
        return {'vertices': [], 'simplices': [], 'equations': [], 'valid': False, 'message': "Points must be 4-dimensional."}

